const cv = document.getElementById('c');
const ctx = cv.getContext('2d');
const modeEl = document.getElementById('mode');
const COLORS = ['#00e5ff', '#b388ff', '#39ff14', '#ff2fb3'];

let W = 0, H = 0, DPR = 1, ps = [];

function spawn(p) {
  p.x = Math.random() * W;
  p.y = Math.random() * H;
  p.px = p.x; p.py = p.y;
  p.c = COLORS[(Math.random() * COLORS.length) | 0];
  p.s = 0.6 + Math.random() * 1.5;
  return p;
}

function resize() {
  DPR = Math.min(2, window.devicePixelRatio || 1);
  W = cv.clientWidth || window.innerWidth;
  H = cv.clientHeight || window.innerHeight;
  cv.width = W * DPR; cv.height = H * DPR;
  ctx.setTransform(DPR, 0, 0, DPR, 0, 0);
  ctx.fillStyle = '#070a0f';
  ctx.fillRect(0, 0, W, H);
  const n = Math.round(Math.min(1100, Math.max(350, (W * H) / 1500)));
  ps = [];
  for (let i = 0; i < n; i++) ps.push(spawn({}));
}
window.addEventListener('resize', resize);

const mouse = { x: -9999, y: -9999, active: false };
window.addEventListener('pointermove', (e) => { mouse.x = e.clientX; mouse.y = e.clientY; mouse.active = true; });
window.addEventListener('pointerleave', () => { mouse.active = false; });

let attract = false;
window.addEventListener('click', () => {
  attract = !attract;
  modeEl.textContent = attract ? '// flow field — attire' : '// flow field — repousse';
});

// Champ de vecteurs « maison » (trigonométrique) qui ondule dans le temps.
const SCALE = 0.0016;
let t = 0;
function field(x, y) {
  return (Math.cos(x * SCALE) + Math.sin(y * SCALE) + Math.sin((x + y) * SCALE * 0.5) + t) * 1.4;
}

const R2 = 16000; // rayon² d'influence de la souris

function tick() {
  t += 0.0016;
  // Voile sombre = traînées qui s'estompent (effet « courants »).
  ctx.globalCompositeOperation = 'source-over';
  ctx.fillStyle = 'rgba(7,10,15,0.075)';
  ctx.fillRect(0, 0, W, H);
  // Rendu additif = superposition néon lumineuse.
  ctx.globalCompositeOperation = 'lighter';
  ctx.lineWidth = 1.1;
  ctx.lineCap = 'round';
  for (const p of ps) {
    const a = field(p.x, p.y);
    let vx = Math.cos(a) * p.s;
    let vy = Math.sin(a) * p.s;
    if (mouse.active) {
      const dx = p.x - mouse.x, dy = p.y - mouse.y;
      const d2 = dx * dx + dy * dy;
      if (d2 < R2) {
        const d = Math.sqrt(d2) || 1;
        const f = (1 - d / Math.sqrt(R2)) * (attract ? -2.6 : 2.6);
        vx += (dx / d) * f;
        vy += (dy / d) * f;
      }
    }
    p.px = p.x; p.py = p.y;
    p.x += vx; p.y += vy;
    if (p.x < 0 || p.x > W || p.y < 0 || p.y > H) { spawn(p); continue; }
    ctx.strokeStyle = p.c;
    ctx.globalAlpha = 0.85;
    ctx.beginPath();
    ctx.moveTo(p.px, p.py);
    ctx.lineTo(p.x, p.y);
    ctx.stroke();
  }
  ctx.globalAlpha = 1;
  requestAnimationFrame(tick);
}

resize();
requestAnimationFrame(tick);

