const $=id=>document.getElementById(id);const field=$('field');
let score=0,time=20,running=false,best=0,timer=null,cur=null;
function hud(){$('score').textContent=score;$('time').textContent=time}
function rand(max){return Math.random()*max}
function spawn(){if(!running)return;if(cur)cur.remove();const size=42+rand(40);const t=document.createElement('button');t.className='target';t.style.width=t.style.height=size+'px';t.style.left=rand(Math.max(1,field.clientWidth-size))+'px';t.style.top=rand(Math.max(1,field.clientHeight-size))+'px';let alive=true;t.onclick=()=>{if(!alive)return;alive=false;score+=Math.round(700/size);hud();spawn()};t.addEventListener('animationend',()=>{if(alive){alive=false;spawn()}});field.appendChild(t);cur=t}
function tick(){time--;hud();if(time<=0)end()}
function start(){score=0;time=20;running=true;hud();$('play').classList.add('hidden');$('over').classList.add('hidden');field.innerHTML='';cur=null;spawn();clearInterval(timer);timer=setInterval(tick,1000)}
function end(){running=false;clearInterval(timer);if(cur){cur.remove();cur=null}best=Math.max(best,score);$('final').textContent=score;$('best').textContent=best;$('over').classList.remove('hidden')}
$('start').onclick=start;$('again').onclick=start;

const c=document.getElementById('m'),x=c.getContext('2d');
let W,H,cols,y;
function init(){W=c.width=innerWidth;H=c.height=innerHeight;cols=Math.floor(W/14);y=Array(cols).fill(0);}
function draw(){x.fillStyle='rgba(7,10,15,.08)';x.fillRect(0,0,W,H);x.fillStyle='#22e39a';x.font='14px monospace';for(let i=0;i<cols;i++){const ch=String.fromCharCode(0x30a0+Math.random()*96);x.fillText(ch,i*14,y[i]*14);if(y[i]*14>H&&Math.random()>.975)y[i]=0;y[i]++;}}
init();addEventListener('resize',init);setInterval(draw,50);
